1	export type Cell = [number, number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: Cell[] = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const survivesOrBorn = (isAlive: boolean, neighbors: number): boolean =>
15	  isAlive ? neighbors === 2 || neighbors === 3 : neighbors === 3;
16	
17	export function nextGeneration(cells: Cell[]): Cell[] {
18	  const liveKeys = new Set(cells.map(cellKey));
19	  const candidates = new Map<string, Cell>();
20	  const neighborCounts = new Map<string, number>();
21	
22	  for (const cell of cells) {
23	    for (const neighbor of neighborsOf(cell)) {
24	      const k = cellKey(neighbor);
25	      candidates.set(k, neighbor);
26	      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
27	    }
28	  }
29	
30	  const result: Cell[] = [];
31	  for (const [k, cell] of candidates) {
32	    if (survivesOrBorn(liveKeys.has(k), neighborCounts.get(k) ?? 0)) {
33	      result.push(cell);
34	    }
35	  }
36	  return result;
37	}
