1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	const sortCells = (cells: Cell[]): Cell[] =>
5	  [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
6	
7	describe("Game of Life - nextGeneration", () => {
8	  it("empty grid stays empty — [] → []", () => {
9	    expect(nextGeneration([])).toEqual([]);
10	  });
11	  it("single live cell dies (underpopulation) — [(0,0)] → []", () => {
12	    expect(nextGeneration([[0, 0]])).toEqual([]);
13	  });
14	  it("two adjacent cells both die (underpopulation, each has 1 neighbor) — [(0,1), (1,1)] → []", () => {
15	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
16	  });
17	  it("block still life remains stable — [(0,0), (1,0), (0,1), (1,1)] unchanged", () => {
18	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
19	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
20	  });
21	  it("live cell with 4+ neighbors dies (overpopulation) — center (1,1) of 3x3 block dies", () => {
22	    const grid: Cell[] = [
23	      [0, 0], [1, 0], [2, 0],
24	      [0, 1], [1, 1], [2, 1],
25	      [0, 2], [1, 2], [2, 2],
26	    ];
27	    const result = nextGeneration(grid);
28	    expect(result).not.toContainEqual([1, 1]);
29	  });
30	  it("dead cell with exactly 3 live neighbors becomes alive (reproduction) — [(0,0),(1,0),(0,1)] gives (1,1) alive", () => {
31	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
32	    expect(result).toContainEqual([1, 1]);
33	  });
34	  it("live cell with 2 neighbors survives (rule 2) — corner (0,0) of L-shape [(0,0),(1,0),(0,1)] survives", () => {
35	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
36	    expect(result).toContainEqual([0, 0]);
37	  });
38	  it("blinker oscillates from vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
39	    const vertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
40	    const expected: Cell[] = [[-1, 1], [0, 1], [1, 1]];
41	    expect(sortCells(nextGeneration(vertical))).toEqual(sortCells(expected));
42	  });
43	  it("handles negative coordinates — blinker at negative offsets oscillates correctly", () => {
44	    const vertical: Cell[] = [[-10, -10], [-10, -9], [-10, -8]];
45	    const expected: Cell[] = [[-11, -9], [-10, -9], [-9, -9]];
46	    expect(sortCells(nextGeneration(vertical))).toEqual(sortCells(expected));
47	  });
48	});
