export function nextGeneration(cells: Cell[]): Cell[] {
  const liveKeys = new Set(cells.map(cellKey));
  const candidates = new Map<string, { cell: Cell; count: number }>();

  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor);
      const entry = candidates.get(key);
      if (entry) {
        entry.count++;
      } else {
        candidates.set(key, { cell: neighbor, count: 1 });
      }
    }
  }

  const result: Cell[] = [];
  for (const [key, { cell, count }] of candidates) {
    if (survivesOrBorn(liveKeys.has(key), count)) {
      result.push(cell);
    }
  }
  return result;
}

